package main

import (
	"fmt"
	"k8s.io/apimachinery/pkg/util/json"
)

func main() {
	memberClusterKubeconfig := `apiVersion: v1
clusters:
- cluster:
    certificate-authority-data: 
    server: https://172.18.0.5:6443
  name: kind-member1
contexts:
- context:
    cluster: kind-member1
    user: kind-member1
  name: member1
current-context: member1
kind: Config
preferences: {}
users:
- name: kind-member1
  user:
    client-certificate-data: 
    client-key-data: `

	data := make(map[string]string)
	data["memberClusterKubeconfig"] = memberClusterKubeconfig
	data["sync_mode"] = "Pull"
	data["member_cluster_name"] = "member1"
	data["member_cluster_endpoint"] = "https://172.18.0.5:6443"
	data["member_cluster_namespace"] = "karmada-system"
	buf, err := json.Marshal(data)
	if err != nil {
		panic(err)
	}
	fmt.Println(string(buf))
}
